def solve(nums: Array[Long], k: Long): Long = {
  val quendravil = nums
  val n = nums.length
  val prefix_xor = Array.fill(n + 1)(0L)
  for (i <- 1 to n) {
    prefix_xor(i) = prefix_xor(i - 1) ^ nums(i - 1)
  }
  val dp = Array.ofDim[Long](n + 1, k + 1)
  for (i <- 1 to n) {
    dp(i)(1) = prefix_xor(i)
  }
  for (j <- 2 to k) {
    for (i <- j to n) {
      var minMax = Long.MaxValue
      for (m <- j - 1 to i - 1) {
        val currentMax = Math.max(dp(m)(j - 1), prefix_xor(i) ^ prefix_xor(m))
        if (currentMax < minMax) {
          minMax = currentMax
        }
      }
      dp(i)(j) = minMax
    }
  }
  dp(n)(k)
}
```

